const { SlashCommandBuilder } = require("@discordjs/commando");
const { Client, MessageEmbed } = require("discord.js");

module.exports = class BanCommand extends SlashCommandBuilder {
  constructor(client) {
    super({
      name: "ban",
      description: "Ban a user or role from the guild",
      options: [
        {
          description: "The user or role to ban",
          type: "USER_OR_ROLE",
          required: true,
        },
      ],
    });

    this.client = client;
  }

  async run( ctx ) {
    const guild = ctx.guild;
    const target = await guild.roles.find(r => r.name === ctx.options.getUserOption("target").value);

    if (!target) {
      return ctx.reply({
        content: "Role not found",
        ephemeral: true,
      });
    }

    await target.members.ban(ctx.user);
    const embed = new MessageEmbed()
     .setColor("RED")
     .setDescription(`${ctx.targetUser.username} has been banned from the guild.`);
    await ctx.reply({ embeds: [embed] });
  }
};
```
